import time
class Timer:
    def __enter__(self):
        self.start = time.time()
        return self
    def __exit__(self, *args):
        print(f"Elapsed: {time.time()-self.start:.3f}s")

with Timer():
    sum(range(1_000_000))

from contextlib import contextmanager

@contextmanager
def timer():
    import time; start = time.time()
    try:
        yield
    finally:
        print(f"Elapsed: {time.time()-start:.3f}s")

with timer():
    sum(range(1_000_000))
